{{/*
Expand the name of the chart.
*/}}
{{- define "url-shortener.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
We truncate at 63 chars because some Kubernetes name fields are limited to this (by the DNS naming spec).
*/}}
{{- define "url-shortener.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "url-shortener.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels
*/}}
{{- define "url-shortener.labels" -}}
helm.sh/chart: {{ include "url-shortener.chart" . }}
{{ include "url-shortener.selectorLabels" . }}
{{- if .Chart.AppVersion }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

{{/*
Selector labels
*/}}
{{- define "url-shortener.selectorLabels" -}}
app.kubernetes.io/name: {{ include "url-shortener.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}

{{- if .Values.serviceAccount.create -}}
apiVersion: v1
kind: ServiceAccount
metadata:
  name: {{ include "url-shortener.fullname" . }}-sa
  namespace: {{ .Release.Namespace }}
  labels:
    {{- include "url-shortener.labels" . | nindent 4 }}
  {{- with .Values.serviceAccount.annotations }}
  annotations:
    {{- toYaml . | nindent 4 }}
  {{- end }}
{{- end }}

apiVersion: v1
kind: Service
metadata:
  name: {{ include "url-shortener.fullname" . }}
  namespace: {{ .Release.Namespace }}
  labels:
    {{- include "url-shortener.labels" . | nindent 4 }}
spec:
  type: {{ .Values.service.type }}
  ports:
    - port: {{ .Values.service.port }}
      targetPort: 8080
      protocol: TCP
      name: http
  selector:
    {{- include "url-shortener.selectorLabels" . | nindent 4 }}

package main

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func TestGenerateRandomCode(t *testing.T) {
	length := 6
	code, err := generateRandomCode(length)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if len(code) != length {
		t.Errorf("expected code length %d, got %d", length, len(code))
	}

	// Verify all characters are within the expected alphanumeric charset
	charset := "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	for _, char := range code {
		if !strings.ContainsRune(charset, char) {
			t.Errorf("unexpected character in code: %c", char)
		}
	}
}

func TestURLShortener_HandleShorten(t *testing.T) {
	shortener := &URLShortener{
		store: make(map[string]string),
	}

	tests := []struct {
		name           string
		body           string
		expectedStatus int
	}{
		{
			name:           "Valid HTTP URL",
			body:           `{"url": "http://example.com/some/path"}`,
			expectedStatus: http.StatusCreated,
		},
		{
			name:           "Valid HTTPS URL",
			body:           `{"url": "https://google.com"}`,
			expectedStatus: http.StatusCreated,
		},
		{
			name:           "Invalid URL scheme",
			body:           `{"url": "ftp://google.com"}`,
			expectedStatus: http.StatusBadRequest,
		},
		{
			name:           "Invalid URL path (no host)",
			body:           `{"url": "relative-path"}`,
			expectedStatus: http.StatusBadRequest,
		},
		{
			name:           "Invalid JSON",
			body:           `{invalid-json}`,
			expectedStatus: http.StatusBadRequest,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			req, err := http.NewRequest("POST", "/shorten", bytes.NewBufferString(tt.body))
			if err != nil {
				t.Fatalf("failed to create request: %v", err)
			}

			rr := httptest.NewRecorder()
			handler := http.HandlerFunc(shortener.handleShorten)
			handler.ServeHTTP(rr, req)

			if rr.Code != tt.expectedStatus {
				t.Errorf("expected status %d, got %d", tt.expectedStatus, rr.Code)
			}

			if tt.expectedStatus == http.StatusCreated {
				var resp ShortenResponse
				if err := json.NewDecoder(rr.Body).Decode(&resp); err != nil {
					t.Fatalf("failed to decode response: %v", err)
				}
				if len(resp.Code) != 6 {
					t.Errorf("expected short code length 6, got %d", len(resp.Code))
				}
				if !strings.Contains(resp.ShortURL, resp.Code) {
					t.Errorf("expected short URL to contain code %s, got %s", resp.Code, resp.ShortURL)
				}
			}
		})
	}
}

func TestURLShortener_HandleRedirect(t *testing.T) {
	shortener := &URLShortener{
		store: map[string]string{
			"test12": "https://example.com/target",
		},
	}

	// 1. Success case
	req, err := http.NewRequest("GET", "/test12", nil)
	if err != nil {
		t.Fatalf("failed to create request: %v", err)
	}

	// Set path value matching Go 1.22 routing
	req.SetPathValue("code", "test12")

	rr := httptest.NewRecorder()
	handler := http.HandlerFunc(shortener.handleRedirect)
	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusFound {
		t.Errorf("expected status 302 Found, got %d", rr.Code)
	}

	location := rr.Header().Get("Location")
	if location != "https://example.com/target" {
		t.Errorf("expected redirect location https://example.com/target, got %s", location)
	}

	// 2. Not found case
	reqNotFound, err := http.NewRequest("GET", "/nonexistent", nil)
	if err != nil {
		t.Fatalf("failed to create request: %v", err)
	}
	reqNotFound.SetPathValue("code", "nonexistent")

	rrNotFound := httptest.NewRecorder()
	handler.ServeHTTP(rrNotFound, reqNotFound)

	if rrNotFound.Code != http.StatusNotFound {
		t.Errorf("expected status 404 Not Found, got %d", rrNotFound.Code)
	}
}

package main

import (
	"context"
	"crypto/rand"
	"encoding/json"
	"fmt"
	"log/slog"
	"math/big"
	"net/http"
	"net/url"
	"os"
	"sync"
	"time"

	secretmanager "cloud.google.com/go/secretmanager/apiv1"
	"cloud.google.com/go/secretmanager/apiv1/secretmanagerpb"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

// Config holds the application configuration
type Config struct {
	ProjectID   string
	SecretName  string
	Environment string
	Port        string
	Host        string
	SecretValue string
}

// URLShortener holds the in-memory database of short codes to long URLs
type URLShortener struct {
	mu    sync.RWMutex
	store map[string]string
}

type ShortenRequest struct {
	URL string `json:"url"`
}

type ShortenResponse struct {
	Code     string `json:"code"`
	ShortURL string `json:"short_url"`
}

var (
	// Prometheus metrics
	httpRequestsTotal = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "url_shortener_http_requests_total",
			Help: "Total number of HTTP requests processed, labeled by status, method, and path.",
		},
		[]string{"status", "method", "path"},
	)
	redirectsTotal = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "url_shortener_redirects_total",
			Help: "Total number of successful short URL redirects, labeled by code.",
		},
		[]string{"code"},
	)
	requestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "url_shortener_request_duration_seconds",
			Help:    "HTTP request latency histogram.",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"method", "path"},
	)
)

func init() {
	// Register Prometheus metrics
	prometheus.MustRegister(httpRequestsTotal)
	prometheus.MustRegister(redirectsTotal)
	prometheus.MustRegister(requestDuration)
}

func main() {
	// 1. Initialize Logger
	env := os.Getenv("ENVIRONMENT")
	var logger *slog.Logger
	if env == "production" || env == "staging" {
		logger = slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{Level: slog.LevelInfo}))
	} else {
		logger = slog.New(slog.NewTextHandler(os.Stdout, &slog.HandlerOptions{Level: slog.LevelDebug}))
	}
	slog.SetDefault(logger)

	// 2. Load Configuration
	config := loadConfig(logger)

	// 3. Initialize URL Shortener store
	shortener := &URLShortener{
		store: make(map[string]string),
	}

	// 4. Setup Routes (Using Go 1.22 wildcard features in ServeMux)
	mux := http.NewServeMux()

	// App API endpoints
	mux.HandleFunc("POST /shorten", shortener.handleShorten)
	mux.HandleFunc("GET /{code}", shortener.handleRedirect)

	// Liveness and Readiness Probes
	mux.HandleFunc("GET /healthz", handleHealthz)
	mux.HandleFunc("GET /health", handleHealthz)

	// Metrics endpoint
	mux.Handle("GET /metrics", promhttp.Handler())

	// Apply Middlewares (Logging, Secure Headers, Metrics)
	wrappedHandler := middlewareMetricsAndHeaders(mux)

	// 5. Start Server
	addr := fmt.Sprintf("%s:%s", config.Host, config.Port)
	slog.Info("Starting server", "addr", addr, "env", config.Environment)

	server := &http.Server{
		Addr:         addr,
		Handler:      wrappedHandler,
		WriteTimeout: 10 * time.Second,
		ReadTimeout:  10 * time.Second,
	}

	if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		slog.Error("Server startup failed", "error", err)
		os.Exit(1)
	}
}

// loadConfig reads configs and resolves secrets from GCP Secret Manager if configured
func loadConfig(logger *slog.Logger) Config {
	config := Config{
		ProjectID:   os.Getenv("GCP_PROJECT_ID"),
		SecretName:  os.Getenv("SECRET_NAME"),
		Environment: os.Getenv("ENVIRONMENT"),
		Port:        os.Getenv("PORT"),
		Host:        os.Getenv("HOST"),
	}

	if config.Port == "" {
		config.Port = "8080"
	}
	if config.Host == "" {
		// Default to localhost for security, but allow 0.0.0.0 when containerized
		config.Host = "127.0.0.1"
		if os.Getenv("CONTAINERIZED") == "true" {
			config.Host = "0.0.0.0"
		}
	}
	if config.SecretName == "" {
		config.SecretName = "url-shortener-secret"
	}

	// Try loading secret from GCP Secret Manager
	if os.Getenv("SECRET_MANAGER_TYPE") == "gcp" && config.ProjectID != "" {
		logger.Info("Attempting to fetch secret from GCP Secret Manager", "project_id", config.ProjectID, "secret_name", config.SecretName)
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		client, err := secretmanager.NewClient(ctx)
		if err != nil {
			logger.Warn("Failed to initialize GCP Secret Manager client, falling back to local env variables", "error", err)
		} else {
			defer client.Close()
			secretPath := fmt.Sprintf("projects/%s/secrets/%s/versions/latest", config.ProjectID, config.SecretName)
			req := &secretmanagerpb.AccessSecretVersionRequest{Name: secretPath}
			result, err := client.AccessSecretVersion(ctx, req)
			if err != nil {
				logger.Warn("Failed to access Secret Manager secret, falling back to local env variables", "error", err, "path", secretPath)
			} else {
				config.SecretValue = string(result.Payload.Data)
				logger.Info("Successfully retrieved secret from GCP Secret Manager")
			}
		}
	}

	// Fallback to local environment variable if SecretValue is still empty
	if config.SecretValue == "" {
		config.SecretValue = os.Getenv("APP_SECRET_VALUE")
		if config.SecretValue == "" {
			logger.Warn("No APP_SECRET_VALUE provided. Running with warning.")
		} else {
			logger.Info("Loaded secret from local environment variable")
		}
	}

	return config
}

// Middleware: Applies security headers, logs requests, and records Prometheus metrics
func middlewareMetricsAndHeaders(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		// Secure Headers
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'none'; frame-ancestors 'none';")

		// Create a custom response writer to capture status code
		sw := &statusWriter{ResponseWriter: w, status: http.StatusOK}

		next.ServeHTTP(sw, r)

		// Record duration metric
		duration := time.Since(start).Seconds()
		requestDuration.WithLabelValues(r.Method, r.URL.Path).Observe(duration)

		// Record total requests metric
		statusStr := fmt.Sprintf("%d", sw.status)
		httpRequestsTotal.WithLabelValues(statusStr, r.Method, r.URL.Path).Inc()

		// Log request details
		slog.Info("Request handled",
			"method", r.Method,
			"path", r.URL.Path,
			"status", sw.status,
			"duration_ms", duration*1000,
			"user_agent", r.UserAgent(),
		)
	})
}

// statusWriter wraps http.ResponseWriter to track status
type statusWriter struct {
	http.ResponseWriter
	status int
}

func (w *statusWriter) WriteHeader(status int) {
	w.status = status
	w.ResponseWriter.WriteHeader(status)
}

// handleHealthz implements the liveness and readiness probe
func handleHealthz(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	_ = json.NewEncoder(w).Encode(map[string]string{"status": "healthy"})
}

// handleShorten accepts a long URL, stores it, and returns the short URL response
func (u *URLShortener) handleShorten(w http.ResponseWriter, r *http.Request) {
	var req ShortenRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		slog.Warn("Failed to decode shorten request body", "error", err)
		http.Error(w, `{"error": "Invalid request body"}`, http.StatusBadRequest)
		return
	}

	// Validate input URL to mitigate SSRF and redirection vulnerabilities
	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil || !parsedURL.IsAbs() || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		slog.Warn("Attempted to shorten invalid URL", "url", req.URL)
		http.Error(w, `{"error": "Invalid URL scheme. Only HTTP and HTTPS are permitted."}`, http.StatusBadRequest)
		return
	}

	// Generate a short code
	code, err := generateRandomCode(6)
	if err != nil {
		slog.Error("Failed to generate short code", "error", err)
		http.Error(w, `{"error": "Internal server error"}`, http.StatusInternalServerError)
		return
	}

	u.mu.Lock()
	u.store[code] = req.URL
	u.mu.Unlock()

	scheme := "http"
	if r.TLS != nil {
		scheme = "https"
	}

	shortURL := fmt.Sprintf("%s://%s/%s", scheme, r.Host, code)

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusCreated)
	_ = json.NewEncoder(w).Encode(ShortenResponse{
		Code:     code,
		ShortURL: shortURL,
	})
}

// handleRedirect redirects the client to the original long URL mapped to the short code
func (u *URLShortener) handleRedirect(w http.ResponseWriter, r *http.Request) {
	// In Go 1.22, wildcards are retrieved using PathValue
	code := r.PathValue("code")

	u.mu.RLock()
	longURL, exists := u.store[code]
	u.mu.RUnlock()

	if !exists {
		slog.Warn("Short code lookup failed", "code", code)
		http.Error(w, `{"error": "Short URL not found"}`, http.StatusNotFound)
		return
	}

	// Increment redirect metric
	redirectsTotal.WithLabelValues(code).Inc()

	// Redirect to the original URL (using 302 Found)
	// TODO(security): The redirect URL is validated on input (/shorten), but we should ensure safety
	http.Redirect(w, r, longURL, http.StatusFound)
}

// generateRandomCode builds a cryptographically secure random alphanumeric string
func generateRandomCode(length int) (string, error) {
	const charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, length)
	for i := range b {
		idx, err := rand.Int(rand.Reader, big.NewInt(int64(len(charset))))
		if err != nil {
			return "", err
		}
		b[i] = charset[idx.Int64()]
	}
	return string(b), nil
}

resource "google_artifact_registry_repository" "repo" {
  location      = var.region
  repository_id = "interview8-repo"
  description   = "Docker registry for URL shortener app"
  format        = "DOCKER"

  labels = {
    environment = var.environment
    owner       = var.owner
    managed_by  = "terraform"
  }
}

resource "google_compute_network" "vpc" {
  name                    = "${var.cluster_name}-vpc"
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "subnet" {
  name          = "${var.cluster_name}-subnet"
  region        = var.region
  network       = google_compute_network.vpc.id
  ip_cidr_range = "10.0.0.0/16"
}

resource "google_container_cluster" "primary" {
  name     = var.cluster_name
  location = var.zone

  # We can't create a cluster without at least one node pool, but we want to
  # delete the default node pool and use a custom one.
  remove_default_node_pool = true
  initial_node_count       = 1

  network    = google_compute_network.vpc.id
  subnetwork = google_compute_subnetwork.subnet.id

  ip_allocation_policy {
    cluster_ipv4_cidr_block  = "/14"
    services_ipv4_cidr_block = "/20"
  }

  workload_identity_config {
    workload_pool = "${var.project_id}.svc.id.goog"
  }

  resource_labels = {
    environment = var.environment
    owner       = var.owner
    managed_by  = "terraform"
  }
}

resource "google_container_node_pool" "primary_nodes" {
  name       = "${var.cluster_name}-node-pool"
  location   = var.zone
  cluster    = google_container_cluster.primary.name
  node_count = 1

  node_config {
    preemptible  = true
    machine_type = "e2-medium"

    service_account = google_service_account.gke_nodes.email
    oauth_scopes = [
      "https://www.googleapis.com/auth/cloud-platform"
    ]

    labels = {
      environment = var.environment
      owner       = var.owner
      managed_by  = "terraform"
    }

    metadata = {
      disable-legacy-endpoints = "true"
    }
  }
}

terraform {
  backend "gcs" {
    # The bucket name is injected dynamically via -backend-config="bucket=..." during terraform init
    prefix = "terraform/state"
  }
}

resource "google_secret_manager_secret" "app_secret" {
  secret_id = "url-shortener-secret"

  replication {
    auto {}
  }

  labels = {
    environment = var.environment
    owner       = var.owner
    managed_by  = "terraform"
  }
}

resource "google_secret_manager_secret_iam_member" "secret_accessor" {
  secret_id = google_secret_manager_secret.app_secret.id
  role      = "roles/secretmanager.secretAccessor"
  member    = "serviceAccount:${google_service_account.app_sa.email}"
}

output "gke_connection_command" {
  value       = "gcloud container clusters get-credentials ${google_container_cluster.primary.name} --zone ${google_container_cluster.primary.location} --project ${var.project_id}"
  description = "The command to update local kubeconfig and connect to the cluster."
}

output "gke_cluster_endpoint" {
  value       = google_container_cluster.primary.endpoint
  description = "The endpoint URL of the GKE cluster."
}

output "artifact_registry_url" {
  value       = "${google_artifact_registry_repository.repo.location}-docker.pkg.dev/${var.project_id}/${google_artifact_registry_repository.repo.repository_id}"
  description = "The URL of the Artifact Registry repository."
}

output "secret_manager_secret_id" {
  value       = google_secret_manager_secret.app_secret.id
  description = "The resource ID of the Secret Manager secret."
}

output "app_service_account_email" {
  value       = google_service_account.app_sa.email
  description = "The email address of the IAM Service Account used by the app."
}

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = var.region
  zone    = var.zone
}

resource "google_service_account" "gke_nodes" {
  account_id   = "${var.cluster_name}-gke-node-sa"
  display_name = "GKE Node Service Account for ${var.cluster_name}"
}

resource "google_project_iam_member" "gke_nodes_logging" {
  project = var.project_id
  role    = "roles/logging.logWriter"
  member  = "serviceAccount:${google_service_account.gke_nodes.email}"
}

resource "google_project_iam_member" "gke_nodes_monitoring_writer" {
  project = var.project_id
  role    = "roles/monitoring.metricWriter"
  member  = "serviceAccount:${google_service_account.gke_nodes.email}"
}

resource "google_project_iam_member" "gke_nodes_monitoring_viewer" {
  project = var.project_id
  role    = "roles/monitoring.viewer"
  member  = "serviceAccount:${google_service_account.gke_nodes.email}"
}

resource "google_project_iam_member" "gke_nodes_registry_reader" {
  project = var.project_id
  role    = "roles/artifactregistry.reader"
  member  = "serviceAccount:${google_service_account.gke_nodes.email}"
}

resource "google_service_account" "app_sa" {
  account_id   = "url-shortener-app-sa"
  display_name = "Service Account for URL Shortener App"
}

resource "google_service_account_iam_member" "workload_identity_binding_staging" {
  service_account_id = google_service_account.app_sa.name
  role               = "roles/iam.workloadIdentityUser"
  member             = "serviceAccount:${var.project_id}.svc.id.goog[staging/url-shortener-sa]"
}

resource "google_service_account_iam_member" "workload_identity_binding_production" {
  service_account_id = google_service_account.app_sa.name
  role               = "roles/iam.workloadIdentityUser"
  member             = "serviceAccount:${var.project_id}.svc.id.goog[production/url-shortener-sa]"
}

variable "project_id" {
  type        = string
  description = "The GCP Project ID where resources will be created."
}

variable "region" {
  type        = string
  description = "The GCP region for provisioning resources."
}

variable "zone" {
  type        = string
  description = "The GCP zone for the GKE cluster node pool."
}

variable "cluster_name" {
  type        = string
  description = "The name of the GKE cluster."
}

variable "owner" {
  type        = string
  description = "The owner tag for the resources."
}

variable "environment" {
  type        = string
  description = "The environment tag (e.g., staging, production)."
}
